{"command": "cd /testbed && python -c "
# Read the file
with open('sympy/ntheory/residue_ntheory.py', 'r') as f:
    content = f.read()

# Find the nthroot_mod function and add the check
old = '''    from sympy.core.numbers import igcdex
    a, n, p = as_int(a), as_int(n), as_int(p)
    if n == 2:
        return sqrt_mod(a, p, all_roots)
    # see Hackman \"Elementary Number Theory\" (2009), page 76
    if not is_nthpow_residue(a, n, p):
        return None'''

new = '''    from sympy.core.numbers import igcdex
    a, n, p = as_int(a), as_int(n), as_int(p)
    if n == 2:
        return sqrt_mod(a, p, all_roots)
    # see Hackman \"Elementary Number Theory\" (2009), page 76
    if a % p == 0:
        return [0] if all_roots else 0
    if not is_nthpow_residue(a, n, p):
        return None'''

if old in content:
    content = content.replace(old, new)
    with open('sympy/ntheory/residue_ntheory.py', 'w') as f:
        f.write(content)
    print('Successfully patched')
else:
    print('Could not find the target text')
"
